// Demo users for deployment (no database required)

export interface DemoUser {
  id: string;
  email: string;
  password: string;
  name: string;
}

export const DEMO_USERS: DemoUser[] = [
  { id: "demo1", email: "user1@example.com", password: "password123", name: "User One" },
  { id: "demo2", email: "user2@example.com", password: "password456", name: "User Two" },
  { id: "demo3", email: "admin@example.com", password: "admin123", name: "Admin" },
];

export function validateDemoUser(email: string, password: string): DemoUser | null {
  const user = DEMO_USERS.find(
    u => u.email === email && u.password === password
  );
  return user || null;
}

export function isDemoEmail(email: string): boolean {
  return DEMO_USERS.some(u => u.email === email);
}